// // This is a 3-bit shift register that captures a single-bit input on each clock cycle. The module shifts the current value of the register to the right and inserts the new input bit at the most significant bit position. The output reflects the current state of the shift register, effectively maintaining the last three bits of input data.
module top_module(
    input clk,       // Added clk input
    input [0:0] in,
    output reg [2:0] out
);reg [2:0] shift_reg;

always @(posedge clk) begin
    shift_reg <= {shift_reg[1:0], in};
end

assign out = shift_reg;

endmodule
